import React, { useState } from 'react';
import api from '../../api/index.js'; // Path ko theek kar diya hai

const FoodLogger = ({ onFoodLogged }) => {
  const [foodName, setFoodName] = useState('');
  const [error, setError] = useState('');
  const [loading, setLoading] = useState(false);

  const onSubmit = async (e) => {
    e.preventDefault();
    if (!foodName) {
      return setError('Please enter a food name.');
    }
    setLoading(true);
    setError('');
    try {
      const res = await api.post('/food/log', { foodName });
      onFoodLogged(res.data);
      setFoodName('');
    } catch (err) {
      // Backend se specific error message dikhayein
      const message = err.response?.data?.message || 'Could not log food. Please try again.';
      setError(message);
      console.error(err);
    } finally {
      setLoading(false);
    }
  };

  return (
    <form onSubmit={onSubmit}>
      {error && <p className="text-red-500 text-sm mb-4">{error}</p>}
      <div className="flex flex-col sm:flex-row gap-4">
        <input
          type="text"
          name="foodName"
          value={foodName}
          onChange={(e) => setFoodName(e.target.value)}
          placeholder="e.g., Roti, Dal, Paneer Bhurji"
          className="flex-grow px-4 py-2 border rounded-md focus:outline-none focus:ring-2 focus:ring-green-500"
        />
        <button
          type="submit"
          className="bg-green-500 text-white px-6 py-2 rounded-md hover:bg-green-600 disabled:bg-gray-400"
          disabled={loading}
        >
          {loading ? 'Logging...' : 'Log Food'}
        </button>
      </div>
    </form>
  );
};

export default FoodLogger;
